static bool isOverflowCheck(const Value *V, Value *&Add, Value *&Op0, Value *&Op1) {
  ICmpInst::Predicate Pred;
  if (!match(V, m_ICmp(Pred, m_Value(Add), m_Value(Op0))) || Pred != ICmpInst::ICMP_ULT)
    return false;
  // Add should be an Add instruction with two operands, one of which is Op0.
  // Actually we need to match Add = add Op0, Op1.
  Value *A, *B;
  if (!match(Add, m_Add(m_Value(A), m_Value(B))))
    return false;
  // Check that Op0 is either A or B.
  if (Op0 != A && Op0 != B)
    return false;
  Op1 = (Op0 == A) ? B : A;
  return true;
